local realmIdToSlugs = {}
for regionId,regionRealms in pairs(RealmSlugs) do
  for lookUpKey, d in pairs(regionRealms.byLookupKey) do
    if realmIdToSlugs[d.id] then
      ns.Debug.print("ERRROROROROROR same id '%s'", d.id)
    end
    realmIdToSlugs[d.id] = d.slug
  end
end

---@class wowutilsPrivate
---@field GetRealmSlug fun(region:number?, realm:string|number):string defaults to own region
---@field GetRealmId fun(region:number?, realm:string|number):number defaults to own region
function ns.GetRealmSlug(region, realm)
  region = region or ns.me.regionId
  if type(realm) == "string" then
    realm = realm:lower():gsub("[^a-z0-9]", "")
    return RealmSlugs[region].byLookupKey[realm].slug or "UNKNOWN"
  end
  realm = tonumber(realm)
  return realm and realmIdToSlugs[realm] or "UNKNOWN"
end

function ns.GetRealmId(region, realm)
  region = region or ns.me.regionId
  if type(realm) == "string" then
    realm = realm:lower():gsub("[^a-z0-9]", "")
    return RealmSlugs[region].byLookupKey[realm] and RealmSlugs[region].byLookupKey[realm].id or 0
  end
  realm = tonumber(realm)
  return realm and realmIdToSlugs[realm] and realm or 0
end